function largest1BorderedSquare(grid) {
    const m = grid.length;
    const n = grid[0].length;
    const horizontal = Array.from({ length: m }, () => Array(n).fill(0));
    const vertical = Array.from({ length: m }, () => Array(n).fill(0));

    let maxSquareSize = 0;

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                horizontal[i][j] = (j === 0) ? 1 : horizontal[i][j - 1] + 1;
                vertical[i][j] = (i === 0) ? 1 : vertical[i - 1][j] + 1;

                let minSize = Math.min(horizontal[i][j], vertical[i][j]);
                while (minSize > maxSquareSize) {
                    if (horizontal[i - minSize + 1][j] >= minSize &&
                        vertical[i][j - minSize + 1] >= minSize) {
                        maxSquareSize = minSize;
                    }
                    minSize--;
                }
            }
        }
    }

    return maxSquareSize * maxSquareSize;
}
```

    1. Create two matrices `horizontal` and `vertical` to store the counts of consecutive 1s from left to right and from top to bottom respectively.
2. Iterate through each element in the `grid`. If the current element is 1, update the respective `horizontal` and `vertical` counts. 
3. Calculate the minimum of the `horizontal` and `vertical` counts, `min_size`.
4. Check if a square subgrid of size `min_size` exists with all 1s on its border. If found, update the `max_square_size`.
5. Check for smaller square sizes by decrementing `min_size`.
6. Finally, return the area of the largest square subgrid found by squaring `max_square_size`. If no such subgrid is found, the result is `0`.

